export type StripeSubscriptionStatus = 'trialing' | 'active' | 'past_due' | 'canceled' | 'unpaid' | 'incomplete' | 'paused';

export interface StripeSubscription {
  id: string;
  customer: string; // customer ID
  status: StripeSubscriptionStatus;
  current_period_start: number; // Unix timestamp
  current_period_end: number; // Unix timestamp
  cancel_at_period_end: boolean;
  items: Array<{
    id: string;
    price: {
      id: string;
      product: string; // product ID
      unit_amount: number;
      currency: string;
    };
    quantity: number;
  }>;
  metadata?: {
    [key: string]: string;
  };
  // Add other relevant fields as needed
}

// Simplified Stripe Event type for demonstration
export interface StripeEvent {
  id: string;
  object: 'event';
  api_version: string;
  created: number;
  data: {
    object: StripeSubscription; // For subscription events, the object is a subscription
    previous_attributes?: Partial<StripeSubscription>;
  };
  livemode: boolean;
  pending_webhooks: number;
  request: {
    id: string;
    idempotency_key: string;
  } | null;
  type: string; // e.g., 'customer.subscription.created', 'customer.subscription.updated', 'customer.subscription.deleted'
}
