import { StripeSubscription } from './types';

/**
 * In-memory "database" for demonstration purposes.
 * In a real application, this would be replaced with a proper database client (e.g., PostgreSQL, MongoDB).
 */
class Database {
  private subscriptions = new Map<string, StripeSubscription>();
  private processedEvents = new Set<string>(); // For idempotency

  public getSubscriptionById(id: string): StripeSubscription | undefined {
    return this.subscriptions.get(id);
  }

  public async updateSubscription(subscription: StripeSubscription): Promise<StripeSubscription> {
    // In a real DB, you'd perform an upsert operation.
    this.subscriptions.set(subscription.id, subscription);
    console.log(`[DB] Subscription ${subscription.id} updated/created. Status: ${subscription.status}`);
    return subscription;
  }

  public async deleteSubscription(id: string): Promise<boolean> {
    const deleted = this.subscriptions.delete(id);
    if (deleted) {
      console.log(`[DB] Subscription ${id} deleted.`);
    }
    return deleted;
  }

  public hasProcessedEvent(eventId: string): boolean {
    return this.processedEvents.has(eventId);
  }

  public addProcessedEvent(eventId: string): void {
    this.processedEvents.add(eventId);
    console.log(`[DB] Event ${eventId} marked as processed.`);
  }
}

export const db = new Database();
