import { db } from '../db';
import { StripeSubscription } from '../types';

/**
 * Service layer for managing subscriptions.
 * This abstracts the database interactions and applies business logic.
 */
class SubscriptionService {
  /**
   * Creates or updates a subscription in the database.
   * @param subscriptionData The subscription data from Stripe.
   * @returns The updated or created subscription.
   */
  public async upsertSubscription(subscriptionData: StripeSubscription): Promise<StripeSubscription> {
    // In a real application, you might map Stripe's subscription object
    // to your internal subscription model here.
    // For this example, we'll use the StripeSubscription type directly.

    const existingSubscription = db.getSubscriptionById(subscriptionData.id);

    if (existingSubscription) {
      console.log(`[SubscriptionService] Updating existing subscription: ${subscriptionData.id}`);
      // Merge or replace fields as necessary.
      // For simplicity, we'll just replace it entirely.
      return db.updateSubscription(subscriptionData);
    } else {
      console.log(`[SubscriptionService] Creating new subscription: ${subscriptionData.id}`);
      return db.updateSubscription(subscriptionData);
    }
  }

  /**
   * Handles a subscription deletion event.
   * In a real app, you might mark it as 'inactive' or 'canceled' rather than deleting.
   * @param subscriptionId The ID of the subscription to delete.
   * @returns True if deleted, false otherwise.
   */
  public async handleSubscriptionDeleted(subscriptionId: string): Promise<boolean> {
    console.log(`[SubscriptionService] Handling deletion for subscription: ${subscriptionId}`);
    // For this example, we'll actually delete it from our in-memory DB.
    // In a production system, you'd likely update its status to 'canceled' or 'deleted'.
    const existingSubscription = db.getSubscriptionById(subscriptionId);
    if (existingSubscription) {
      existingSubscription.status = 'canceled'; // Mark as canceled instead of full delete
      await db.updateSubscription(existingSubscription);
      return true;
    }
    return false;
  }
}

export const subscriptionService = new SubscriptionService();
