import { stripe } from '../stripe';
import { STRIPE_WEBHOOK_SECRET } from '../config';
import { db } from '../db';
import { subscriptionService } from '../services/subscriptionService';
import { StripeEvent, StripeSubscription } from '../types';

/**
 * Handles incoming Stripe webhook events.
 * Verifies the signature, parses the event, and dispatches to appropriate services.
 * @param rawBody The raw request body as a string.
 * @param signature The value of the 'stripe-signature' header.
 * @returns A promise that resolves to a success message or rejects with an error.
 */
export async function handleStripeWebhook(rawBody: string, signature: string): Promise<string> {
  let event: StripeEvent;

  try {
    // Verify the event signature and construct the event object
    event = stripe.webhooks.constructEvent(rawBody, signature, STRIPE_WEBHOOK_SECRET!) as StripeEvent;
  } catch (err: any) {
    console.error(`[StripeWebhookHandler] Webhook signature verification failed: ${err.message}`);
    throw new Error(`Webhook Error: ${err.message}`);
  }

  // Idempotency check: Ensure we don't process the same event twice
  if (db.hasProcessedEvent(event.id)) {
    console.log(`[StripeWebhookHandler] Event ${event.id} already processed. Skipping.`);
    return `Event ${event.id} already processed.`;
  }

  // Mark event as processed before handling to prevent race conditions
  db.addProcessedEvent(event.id);

  console.log(`[StripeWebhookHandler] Received Stripe event: ${event.type} (ID: ${event.id})`);

  try {
    switch (event.type) {
      case 'customer.subscription.created':
      case 'customer.subscription.updated': {
        const subscription = event.data.object as StripeSubscription;
        await subscriptionService.upsertSubscription(subscription);
        break;
      }
      case 'customer.subscription.deleted': {
        const subscription = event.data.object as StripeSubscription;
        await subscriptionService.handleSubscriptionDeleted(subscription.id);
        break;
      }
      // Add more event types as needed (e.g., 'invoice.payment_succeeded', 'checkout.session.completed')
      default: {
        console.warn(`[StripeWebhookHandler] Unhandled event type: ${event.type}`);
        break;
      }
    }
  } catch (error: any) {
    console.error(`[StripeWebhookHandler] Error processing event ${event.id} (${event.type}):`, error.message);
    // In a real application, you might want to re-queue this event or send an alert.
    throw new Error(`Error processing event: ${error.message}`);
  }

  return `Successfully handled event ${event.id} of type ${event.type}.`;
}
