import { Hono } from 'hono';
import { handleStripeWebhook } from './handlers/stripeWebhookHandler';
import { PORT } from './config';

const app = new Hono();

// Middleware to parse raw body for Stripe webhooks
// Hono's default body parser might consume the stream, preventing Stripe from verifying the raw body.
// We need to ensure the raw body is available as text.
app.use('/webhook/stripe', async (c, next) => {
  if (c.req.method === 'POST') {
    // Store the raw body in a custom property for later access
    // Hono's c.req.text() reads the body once.
    (c.req as any).rawBody = await c.req.text();
  }
  await next();
});

app.post('/webhook/stripe', async (c) => {
  const rawBody = (c.req as any).rawBody;
  const signature = c.req.header('stripe-signature');

  if (!rawBody || !signature) {
    console.error('[App] Missing raw body or Stripe-Signature header.');
    return c.json({ error: 'Missing raw body or Stripe-Signature header' }, 400);
  }

  try {
    const result = await handleStripeWebhook(rawBody, signature);
    return c.json({ received: true, message: result }, 200);
  } catch (error: any) {
    console.error('[App] Error handling Stripe webhook:', error.message);
    return c.json({ error: error.message }, 400);
  }
});

app.get('/', (c) => {
  return c.text('Stripe Webhook Handler is running!');
});

console.log(`Server running on http://localhost:${PORT}`);
console.log('Stripe webhook endpoint: POST /webhook/stripe');

export default {
  port: parseInt(PORT as string),
  fetch: app.fetch,
};
